        value: to_string($message.app_message)
    );
    set_field("heat_entity_type", m["0"]);
    set_field("heat_entity_uuid", m["1"]);
end

rule "HV - HTTP API version extraction"
when
    has_field("http_path") AND
    regex("^/(v[0-9]+(?:\\.[0-9]+)?)/", to_string($message.http_path)).matches == true
then
    let m = regex(
        pattern: "^/(v[0-9]+(?:\\.[0-9]+)?)/",
        value: to_string($message.http_path)
    );
    set_field("http_api_version", m["0"]);
end

rule "HE - HTTP endpoint resource type (Neutron/Nova/Cinder)"
when
    has_field("http_path") AND
    regex("^/v[0-9.]+/([a-z_-]+)", to_string($message.http_path)).matches == true
then
    let m = regex(
        pattern: "^/v[0-9.]+/([a-z_-]+)",
        value: to_string($message.http_path)
    );
    set_field("http_resource", m["0"]);
end
